sql:
SELECT hotel_name, rating
FROM hotels
ORDER BY rating DESC;

SELECT COUNT(*)
FROM reviews
WHERE hotel_id = (SELECT hotel_id FROM hotels WHERE hotel_name = 'Desired Hotel Name');

SELECT hotel_name, location, rating
FROM hotels
ORDER BY rating DESC;

SELECT AVG(rating) AS average_rating
FROM hotels
WHERE location = 'Bageshwar';

SELECT COUNT(*)
FROM staff
WHERE performance_score > 80;
